{
  "envelope_version": "charness.run_plan_envelope.v1",
  "gate_packets": [
    {
      "command": "./scripts/run-quality.sh --read-only",
      "cost_tier": "broad",
      "id": "read-only-quality",
      "parallel_group": "serial-critical",
      "purpose": "standing deterministic evidence packet",
      "run_after": "required-primer",
      "run_when": "repo exposes this repo-native command or an equivalent standing quality gate",
      "trust_model": "hard gate plus advisory sub-packets; green is evidence, not judgment"
    },
    {
      "command": "python3 \"$SKILL_DIR/scripts/render_runtime_summary.py\" --repo-root . --json",
      "cost_tier": "cheap",
      "id": "runtime-summary",
      "parallel_group": "inventories",
      "purpose": "measured runtime trend source before claiming cost or speed facts",
      "run_when": "runtime, slow gate, budget, or cost is in scope",
      "trust_model": "measurement packet"
    },
    {
      "command": "python3 \"$SKILL_DIR/scripts/inventory_skill_ergonomics.py\" --repo-root . --summary",
      "cost_tier": "cheap",
      "id": "skill-ergonomics",
      "parallel_group": "inventories",
      "purpose": "advisory skill-surface pressure packet when skills are in scope",
      "run_when": "skills_in_scope",
      "trust_model": "heuristic advisory with false positives and false negatives"
    }
  ],
  "gate_plan": "report_first",
  "next_action": {
    "kind": "read_primer_refs"
  },
  "on_demand_reads": [
    {
      "path": "references/adapter-contract.md",
      "role": "on-demand",
      "trigger": "adapter missing, invalid, stale, or under-specified"
    },
    {
      "path": "references/adapter-gate-review.md",
      "role": "on-demand",
      "trigger": "adapter or gate recommendation needs enforcement-tier review"
    },
    {
      "path": "references/agent-production-runtime.md",
      "role": "on-demand",
      "trigger": "production agent runtime, provider policy, fallback, telemetry, or serving-path risk"
    },
    {
      "path": "references/dup-ratchet.md",
      "role": "on-demand",
      "trigger": "dup-ratchet failure, scanner skew, baseline update, or clone-family interpretation"
    },
    {
      "path": "references/bootstrap-escalations.md",
      "role": "on-demand",
      "trigger": "bootstrap path needs non-default escalation, hidden setup work, adapter repair, or operator-facing bootstrap judgment"
    },
    {
      "path": "references/bootstrap-posture.md",
      "role": "on-demand",
      "trigger": "quality adapter bootstrap or setup-state repair"
    },
    {
      "path": "references/boundary-bypass-ratchet.md",
      "role": "on-demand",
      "trigger": "boundary-bypass inventory, ratchet, or exemption review"
    },
    {
      "path": "references/brittle-source-guards.md",
      "role": "on-demand",
      "trigger": "brittle source guard finding or matcher migration"
