    {
      "path": "references/standing-gate-verbosity.md",
      "role": "on-demand",
      "trigger": "standing gate output, runtime, progress signal, or failure detail review"
    },
    {
      "path": "references/testability-and-selection.md",
      "role": "on-demand",
      "trigger": "slow tests, affected-test selection, mutation workload, or broad test economics"
    },
    {
      "path": "references/cautilus-on-demand.md",
      "role": "on-demand",
      "trigger": "cautilus evaluate fixture, observation, or skill-experiment is being considered"
    },
    {
      "path": "references/behavior-testing.md",
      "role": "on-demand",
      "trigger": "deterministic gates cannot honestly prove an agent/user behavior seam"
